class Solution { public: int longestIncreasingPath(vector<vector<int>>& matrix) { int N = matrix.size(), M = matrix[0].size(); vector<vector<bool>> memo(N, vector<bool>(M, false)); function<int(int, int)> dfs = [&](int i, int j) { if (memo[i][j]) return memo[i][j]; int ans = 1; for (int x = -1; x <= 1; x++) for (int y = -1; y <= 1; y++) { if (x == 0 && y == 0) continue; int ni = i + x, nj = j + y; if (ni >= 0 && ni < N && nj >= 0 && nj < M && matrix[ni][nj] > matrix[i][j]) ans = max(ans, 1 + dfs(ni, nj)); } memo[i][j] = true; return ans; }; for (int i = 0; i < N; i++) for (int j = 0; j < M; j++) memo[i][j] = false; for (int i = 0; i < N; i++) for (int j = 0; j < M; j++) dfs(i, j); return *max_element(begin(memo[0]), end(memo[0])); } }; int main() { std::ios_base::sync_with_stdio(false); std::cin.tie(nullptr); std::vector<std::string> lines; std::string line; while (std::getline(std::cin, line)) lines.push_back(line); std::istringstream iss; int N, M; for (const auto& line : lines) if (line.length()) { iss.clear(); iss.str(line); iss >> N >> M; break; } std::vector<std::vector<int>> matrix(N, std::vector<int>(M)); int num; for (int i = 0; i < N; i++) for (int j = 0; j < M; j++) { std::cin >> num; matrix[i][j] = num; } Solution solution; std::cout << solution.longestIncreasingPath(matrix) << '
